command.text:
        &CommandCheckLockedDate;
        &CommandCheckTaxCodeBeforeSave;

declare @@master nvarchar(32)
select @@master = '@@table'
&CommandGetIdentityNumber;
if @ma_nt = @baseCurrency select @ma_nt = '', @ty_gia = 0
select @ma_ct = @@id, @datetime0 = getdate(), @datetime2 = getdate(), @user_id0 = @@userID, @user_id2 = @@userID

        &CommandCheckTaxCodeBeforeSave;

if not exists(select * from @@table where stt_rec = @stt_rec) begin
  select @$recordHasBeenChanged as message
  return
end

        &CommandCheckLockedDate;


if @ma_nt = @baseCurrency update @@table set ma_nt = '', @ty_gia = 0, datetime2 = getdate(), user_id2 = @@userID where stt_rec = @stt_rec
  else update @@table set datetime2 = getdate(), user_id2 = @@userID where stt_rec = @stt_rec

        &CommandListCheckTaxCodeWarning;

script.text:
      &ScriptCheckTaxCode;
      /* <flatten type="Javascript"> */
function activeForm(f) {
  f._controlFocus = f.getItem('ngay_ct');
  f.add_onResponseComplete(on$Form$ResponseComplete);
  f.$a = {
    t_tien2: '[t_tien2]:= [t_tien_nt2]*[ty_gia]',
    t_thue_nt: '[t_thue_nt]:= ([t_tien_nt2]*[thue_suat])/100',
    t_thue: '[t_thue]:= ([t_tien2]*[thue_suat])/100',
    t_thue_tg: '[t_thue]:= [t_thue_nt]*[ty_gia]'
  };
  f._tabContainer.add_activeTabChanged(onTabChanged);
  f._tabContainer._loaded = true;
  if (f._action == 'New') {
    f.getItem('ma_mau_ct').value = f._vCode;
    f.getItem('ten_mau_ct%l').value = f._vName;
  };
}
function initForm(f) {
  if (f._action == 'New') {
    var o = f.getItem('ma_dvcs');
    o.value = f._unitCode;
    f.getItem('ten_dvcs%l').value = f._unitName;
    f.getItem('ma_thue').value = f._taxCode;
    f.getItem('tk_thue_co').value = f._taxAccount;
    f.getItem('ten_tk_thue_co%l').value = f._taxAccountName;
    f.getItem('thue_suat').value = f._taxRate;
  }
  f.setReferenceKeyFilter('ma_kho');
  if ($func.trim(f.getItemValue('ma_nt')) == '') f.setItemValue('ma_nt', f._baseCurrency);
  onChangeCurrency(f);
}
function closeForm(f) {
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onTabChanged);} catch (ex) {}
  try {f.remove_onResponseComplete(on$Form$ResponseComplete);} catch (ex) {}
}
function onTabChanged(sender, e) {sender.parentForm.focusWhenTabChanged(['ma_kh', 'ma_nvbh']);}
function onChangeCurrency(f) {
  var c = f.getItemValue('ma_nt').toUpperCase();
  var v = (c == '' || c == f._baseCurrency);
  if (v) {
    f.setItemValue('t_tien_nt2', 0);
    f.setItemValue('t_thue_nt', 0);
    f.setItemValue('ty_gia', 1);
  }
  f.getItem('t_tien_nt2').disabled = f.getItem('t_thue_nt').disabled = f.getItem('ty_gia').disabled = v;
}
function onChange$Form$Item(o) {
  var f = o.parentForm, name = o.field.Name;
  switch (name) {
    case 'ma_kh':
      f.request('Customer', 'Customer', ['ma_kh'], o);
      break;
    case 'ma_thue':
      f.request('GetTaxRate', 'GetTaxRate', ['ma_thue'], o);
      break;
    case 'ngay_ct':
      f.setItemValue('ngay_lct', f.getItemValue('ngay_ct'));
      f.live(f.getItem('ngay_lct'));
      break;
    case 'ma_nt':
      onChangeCurrency(f);
      setFocusWhenCurrencyChange(f);
      break;
    case 'ty_gia':
      f.executeExpression([f.$a.t_tien2, f.$a.t_thue]);
      break;
    case 't_tien_nt2':
      f.executeExpression([f.$a.t_tien2, f.$a.t_thue_nt, f.$a.t_thue]);
      f.live(f.getItem('t_tien2'));
      break;
    case 't_tien2':
      f.executeExpression([f.$a.t_thue]);
      break;
    case 't_thue_nt':
      f.executeExpression([f.$a.t_thue_tg]);
      f.live(f.getItem('t_thue'));
      break;
    default:
      break;
  }
}
function on$Form$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Customer':
      f.setItemControlBehavior('ten_kh', result[0].Value, null, true);
      f.setItemControlBehavior('dia_chi', result[1].Value, null, true);
      f.setItemControlBehavior('ma_so_thue', result[2].Value, null, true);
      f.live(f.getItem('ten_kh'));
      break;
    case 'GetTaxRate':
      var r = result[0].Value;
      if (f.getItemValue('thue_suat') != r) {
        f.setItemValue('thue_suat', r);
        f.executeExpression([f.$a.t_thue_nt, f.$a.t_thue]);
        f.live(f.getItem('t_thue_nt'));
        f.live(f.getItem('t_thue'));
      }
      f.setItemControlBehavior('tk_thue_co', result[1].Value, result[2].Value, true);
      break;
    default:
      break;
  }
}
function setFocusWhenCurrencyChange(f) {
  var c = f.getItemValue('ma_nt').toUpperCase();
  var n = (c == '' || c == f._baseCurrency) ? 't_tien2' : 'ty_gia';
  var o = f.getItem(n);
  try {o.focus(); f.live(o);} catch (ex) {}
}
/* </flatten> */
